import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISAIAH = {'19': {'1': "<p>YHWH rides on a swift cloud to Egypt — the theophanic cloud-chariot is the vehicle of the divine warrior (Ps 68:4, 104:3; Dan 7:13). The idols of Egypt tremble at his approach and the heart of Egypt melts. The coming-on-a-cloud image is the same vocabulary Jesus uses in the Olivet Discourse (Matt 24:30: the Son of Man coming on the clouds) and that Daniel 7:13 applies to the one like a son of man. YHWH's coming to Egypt in judgment is a type of the final coming of the Son: every idol that claims ultimate loyalty will tremble before the one who comes on the cloud.</p>", '2': "<p>YHWH stirs up Egyptians against Egyptians — civil war as covenant judgment. The internal collapse of a civilization is YHWH's judgment tool: he removes the social cohesion that holds a society together, and it fractures along its fault lines. The NT application: Jesus says he came not to bring peace but a sword, and that families will be divided against each other (Matt 10:34-36). The division YHWH brings is not cruelty but the inevitable consequence of rejecting the one who is the source of all true peace (shalom).</p>", '3': "<p>Egypt's spirit (<em>ruach</em>) will drain away; YHWH will confound its plans; the Egyptians will turn to idols and mediums. The spirit-draining is the withdrawal of the divine breath that sustains wisdom and governance. The flight to idols and necromancers follows: when YHWH withdraws, people fill the vacuum with occult practices. The NT pattern: the wisdom of this world is foolishness with God (1 Cor 3:19); those who suppress the truth in unrighteousness exchange the living God for images (Rom 1:21-23). Egypt's turn to mediums is the extreme form of what every society does when it rejects YHWH.</p>", '4': '<p>YHWH hands Egypt over to a harsh master, a cruel king. The handing-over (<em>sakkar</em>) is the same verb as the divine hardening that leads to judgment: YHWH gives a people over to the consequences of rejecting him (Rom 1:24, 26, 28: God gave them over). The cruel king is the form human rebellion produces when YHWH removes his restraining hand. In the Christological framework: the only alternative to the kingship of the Servant-King (9:6-7) is the tyranny of the cruel king.</p>', '5': "<p>The Nile will dry up. The river that was Egypt's life-source, the basis of its agriculture and economy, will be parched. The drying of Egypt's waters is the anti-creation judgment: the same God who made water teem with life (Gen 1:20-21) withdraws the water when his people are judged. In contrast, the promise to those who follow YHWH is the springs of salvation (12:3) and rivers of living water (John 7:38) — the Servant's presence reverses the parching that judgment produces.</p>", '6': "<p>The channels will become foul; the Nile's branches will shrink and dry up; reeds and rushes will wither. The ecological collapse of Egypt follows from the Nile's failure: everything dependent on the water-source dies. This is the prophetic image of what happens to any civilization when its spiritual foundation is removed — the surface vegetation survives briefly, then withers completely. The NT uses the same image: the branch that does not remain in the vine withers and is thrown into the fire (John 15:6).</p>", '7': "<p>Papyrus reeds and crops along the Nile will wither, blow away, and cease to be. The drying of the Nile produces a windswept desolation where Egypt's abundant agriculture once flourished. The contrast with the new-creation promise (35:7: the burning sand will become a pool; water will gush in the desert) marks this as the judgment-side of the Isaianic pattern: YHWH dries up when he judges, waters when he redeems.</p>", '8': "<p>Fishermen will mourn; those who cast hooks into the Nile and spread nets on the water will languish. Egypt's fishing economy was famous in the ancient world — the Nile's fish were a dietary staple mourned during the wilderness years (Num 11:5). The fishermen's mourning is the economic face of covenant judgment: the work of human hands fails when YHWH withdraws provision. In the NT, Jesus calls fishermen to become fishers of men (Matt 4:19) — the same economic vocabulary applied to the kingdom: the divine economy provides what the natural economy, under judgment, cannot.</p>", '9': "<p>Those who work with combed flax and weave fine linen will be put to shame. Egypt's linen industry was world-famous (Gen 41:42; Ezek 27:7). Its destruction is a specific economic judgment: the goods Egypt was proud of producing will be stopped. The shame is both economic and cultural: a civilization's identity is bound up in what it makes. The NT equivalent: those who build with wood, hay, and stubble will see their work burned at the judgment (1 Cor 3:12-15) — only what is built on the foundation of Christ survives.</p>", '10': "<p>Egypt's foundations will be crushed; all who work for hire will be sick at heart. The foundations (<em>shototeha</em>) — the structural supports of Egyptian civilization — are broken. The wage-worker who cannot earn is the last resort of the hierarchy, and when they despair, the whole system has collapsed. In the NT pattern: the laborers in the vineyard receive their wage from the master (Matt 20:1-16) — YHWH's economy pays justly, even unexpectedly. Egypt's wage-workers have no such master.</p>", '11': "<p>The princes of Zoan are utter fools; Pharaoh's wisest counselors give worthless advice. The wisdom tradition of Egypt was ancient and prestigious — yet it is confounded by YHWH's judgment. How can they claim to be wise? — the question is rhetorical: Egypt's wisdom cannot interpret what YHWH is doing. Paul applies this directly: where is the wise man? Where is the scholar? Has not God made foolish the wisdom of the world? (1 Cor 1:20). Isaiah 19:11-15 is the OT ground for Paul's theology of the cross as foolishness to the wise.</p>", '12': "<p>Where are your wise men now? Let them tell you what YHWH of hosts has planned against Egypt. The prophetic challenge to wisdom: if the wise men are truly wise, let them interpret the divine plan. The irony is that YHWH's plan (vv 19-25) is so unexpected — YHWH blessing Egypt as my people — that no human wisdom could have derived it. It took revelation, not reason. The NT ground is 1 Cor 2:6-10: what no eye has seen, ear heard, or mind conceived — God has revealed by his Spirit.</p>", '13': "<p>The princes of Zoan and Memphis have made themselves fools; the leaders of Egypt's tribes have led it astray. The leaders who should have guided the nation are themselves deluded. The leadership failure of Egypt mirrors the leadership failure of Jerusalem in chapters 1-6: when the guides are blind, the nation stumbles. Jesus applies this to the Pharisees: they are blind guides; if the blind lead the blind, both fall into the pit (Matt 15:14).</p>", '14': '<p>YHWH has poured into Egypt a spirit (<em>ruach</em>) of confusion; the Egyptians err in everything they do, like a drunkard reeling in his vomit. The divine sending of a spirit of confusion recalls the lying spirit in 1 Kgs 22:19-23 — YHWH uses spiritual confusion as a judgment instrument. The drunkard-in-vomit image is the most extreme of the confusion descriptions: complete disorientation, incapable of directed action. The NT equivalent: God sends a powerful delusion to those who refuse to love the truth (2 Thess 2:11) — the same pattern of judgment through confusional darkening.</p>', '15': "<p>Nothing Egypt can accomplish — neither head nor tail, neither palm branch nor reed. The head-to-tail formula (echoing 9:14-15) means from the highest to the lowest rank: every level of Egyptian society is incapacitated. The palm branch and reed symbolize height and humility, nobility and common folk. The total paralysis of Egypt by YHWH's judgment is the dark image of what the coming of the Branch (tsemach, 4:2) reverses: the Servant gives sight to the blind and freedom to the captive (61:1), restoring what YHWH's judgment removed.</p>", '16': "<p>In that day the Egyptians will be like frightened women, trembling because of the hand of YHWH of hosts that he is raising against them. The first in-that-day oracle (vv 16-25) begins with judgment but moves toward unprecedented blessing. The trembling of Egypt is not its final state — what begins in fear (v 16) ends in worship (vv 21-22). The same YHWH whose judgment produces trembling is the one whose salvation produces the doxology of 12:1-6. The fear of YHWH is the beginning of wisdom (Prov 9:10), and Egypt's trembling is the first step toward its restoration.</p>", '17': "<p>The land of Judah will become a source of dread to Egypt — whenever Judah is mentioned, Egypt will tremble because of what YHWH of hosts has planned against it. The reversal: Egypt, the superpower that held Israel as slaves, will fear the mention of Judah. This is the Deut 28:13 blessing: YHWH will make you the head, not the tail; you will be above, not below. In the Christological trajectory, the reversal reaches its completion when the nations stream to Zion (2:2-3) not in fear but in seeking YHWH's instruction — the same nations, but now drawn by glory rather than repelled by judgment.</p>", '18': "<p>In that day five cities in Egypt will speak the language of Canaan and swear loyalty to YHWH of hosts. The language of Canaan is Hebrew — the covenant tongue. Egypt's cities swearing allegiance to YHWH is the most radical reversal: the nation that enslaved Israel now adopts Israel's language and Israel's God. The NT fulfillment: at Pentecost, people from every nation hear the gospel in their own tongue (Acts 2:8-11), but all are united in calling on the name of the Lord (Joel 2:32, Acts 2:21). The five Egyptian cities are the type of the nations that will bear YHWH's name.</p>", '19': "<p>In that day there will be an altar to YHWH in the heart of Egypt and a standing stone at its border dedicated to YHWH. The altar in Egypt's heart is extraordinary: the place of Israel's slavery becomes a place of YHWH's worship. The altar is the intersection of human approach and divine presence — and YHWH places one in the center of the enemy empire. The NT: every place where the church gathers is an altar of the new covenant, and the church's mission (from Jerusalem to the ends of the earth, Acts 1:8) is the outworking of this oracle — taking the altar of YHWH to Egypt and beyond.</p>", '20': "<p>The altar will be a sign and witness to YHWH of hosts in Egypt. When they cry to YHWH because of oppressors, he will send them a savior and defender to rescue them. The savior-and-defender sent to Egypt in response to their cry is the exodus pattern applied to Egypt itself: YHWH heard Israel's cry in Egypt and sent Moses (Exod 3:7-8). Now YHWH will hear Egypt's cry in Egypt and send a savior. The one savior-and-defender who fulfills this universally is the Servant: he will not falter until he establishes justice in the earth; the islands will put their hope in his teaching (42:4).</p>", '21': "<p>YHWH will make himself known to Egypt, and the Egyptians will acknowledge YHWH in that day. They will worship with sacrifice and grain offering; they will make vows to YHWH and keep them. The Egyptians worshipping YHWH with proper sacrificial rites — the full covenant cultus — is the eschatological inclusion of Egypt in the covenant. The NT: Jesus commands baptizing and teaching all nations (Matt 28:19); Paul's mission in Acts includes Egypt's territory; the new Jerusalem has gates open to all nations (Rev 21:24-26). Egypt's worship of YHWH with sacrifice is fulfilled in the Messiah's sacrifice received by all peoples.</p>", '22': '<p>YHWH will strike Egypt — striking and healing — and they will turn back to YHWH. He will hear their pleas and heal them. The striking-and-healing dialectic is the pattern of covenant relationship: discipline that produces repentance that produces restoration. Hosea applies the same pattern to Israel (Hos 6:1: he has torn us to pieces, but he will heal us). The NT ground is Heb 12:6: the Lord disciplines the one he loves. The healing of Egypt by YHWH is the universal pattern of how YHWH redeems any people — through judgment toward repentance toward restoration.</p>', '23': "<p>In that day there will be a highway from Egypt to Assyria — the two great empires that bookended Israel's history, the oppressors of the south and the north — will be connected by a road of peaceful exchange. The highway reverses the roads of conquest: what was a path for invading armies becomes a route for mutual blessing. The great highway of 40:3 (prepare in the wilderness a highway for our God) is the spiritual counterpart. In the NT, the dividing wall of hostility between Jew and Gentile is abolished in Christ (Eph 2:14-16); the Egypt-Assyria highway is the type of the reconciliation of all enemies in the peace of the Messiah.</p>", '24': "<p>In that day Israel will be the third alongside Egypt and Assyria, a blessing in the midst of the earth. Israel — not the superpower, but the middle member of the triad — fulfills the Abrahamic commission: through you all families of the earth will be blessed (Gen 12:3). The three former enemies stand together as YHWH's community of blessing. The NT: the church as the body composed of Jew and Gentile (Eph 2:15-16) is the eschatological fulfillment of this triad — the middle wall broken down, former enemies joined in one new humanity.</p>", '25': "<p>Blessed be Egypt my people, and Assyria the work of my hands, and Israel my inheritance. The three titles used here — my people, the work of my hands, my inheritance — are the titles used throughout Isaiah and the OT for Israel alone. Now YHWH applies each to a different nation: Egypt receives the covenant-intimacy title (my people), Assyria receives the creation-relationship title (the work of my hands), and Israel keeps the inheritance title. The NT: the wall between Jew and Gentile, Israel and the nations, comes down in Christ; all who are in Christ are Abraham's seed and heirs according to the promise (Gal 3:29). This verse is the most universalist in Isaiah — and its fulfillment is the church gathered from every nation.</p>"}, '20': {'1': "<p>The historical anchor: the year Sargon of Assyria sent his commander-in-chief to attack Ashdod. The specific historical detail grounds the sign-act of vv 2-6 in a documented event (Sargon's campaign of 711 BCE). The prophet's body becomes the medium of revelation in the most visceral way: Isaiah's physical condition over three years is the message YHWH communicates to Israel. The NT equivalent: the incarnation itself is the ultimate sign-act in which the divine being takes on the conditions of human vulnerability to deliver a message that no verbal oracle could match.</p>", '2': "<p>YHWH speaks through Isaiah: go, remove the sackcloth and take off your sandals. Isaiah obeyed — he walked naked and barefoot. The sackcloth that Isaiah removes was probably his normal prophetic garb (cf. Zech 13:4). The nakedness and barefoot-ness are the marks of captivity and poverty — the condition of prisoners taken in war. By wearing these conditions for three years, Isaiah embodies the fate that awaits those who trust Egypt and Cush. The NT sign-act equivalent: Jesus' own body is the sign — the teacher who had nowhere to lay his head (Matt 8:20), stripped at Golgotha (John 19:23), is the living embodiment of what judgment looks like when it falls on the one who takes it on behalf of others.</p>", '3': "<p>YHWH interprets: just as Isaiah has walked naked and barefoot for three years as a sign and portent against Egypt and Cush. The three years are deliberate: not a brief symbolic action but a sustained embodiment. The sign (<em>ot</em>) and portent (<em>mofet</em>) are the two terms used for the plagues of Egypt (Exod 7:3) — the prophetic act recapitulates the exodus judgment, now applied to Egypt itself. Isaiah's body is a living prophecy: the prophet who speaks of the Servant's suffering (52:13-53:12) first enacts a lesser version of stripping and humiliation.</p>", '4': "<p>The king of Assyria will lead away Egyptian and Cushite captives naked and barefoot, with buttocks uncovered — the shame of Egypt exposed. The explicit shameful exposure of the captives is the judgment that Isaiah's three years of symbolic nakedness has been announcing. In the Christological pattern: the Servant is stripped and shamed in a way that should belong to others (52:14; 53:3-4) — his exposure is substitutionary, taking on what the rebels deserve. Isaiah's years of nakedness are a prophetic type of the Servant's ultimate stripping.</p>", '5': '<p>Those who looked to Cush with expectation and took pride in Egypt will be terrified and put to shame. The political trust in Egypt — the alliance that seemed pragmatically wise — is the precise thing condemned. The shame is proportional to the hope: the greater the expectation placed in Egypt, the greater the humiliation when Egypt falls. In the NT, the same logic applies to any trust placed in human strength: those who make flesh their strength (17:5) will be ashamed when the arm of flesh fails.</p>', '6': "<p>In that day the coastland people will say: This is what happened to those we relied on, to whom we fled for help and rescue from the king of Assyria — how will we escape? The confession of the coastlands is the universal admission that human political alliances cannot save. The three-year sign-act concludes with this admission. The NT ground: blessed are those who trust in YHWH (Jer 17:7); cursed is the one who trusts in man (Jer 17:5-6). The coastlands' question — how will we escape? — is the question that the gospel answers: not by any political alliance but by the one who has already faced the Assyrian-equivalent and overcome (cf. 37:36).</p>"}, '21': {'1': "<p>The oracle of the Desert of the Sea — a cryptic designation for Babylon. Like whirlwinds in the Negeb, this vision comes from the desert, from a dreadful land. The whirlwind from the south is YHWH's judgment-storm, and its direction (from the desert, the wilderness between Babylon and Canaan) signals the direction from which Cyrus will come. The oracle's cryptic title (Desert of the Sea) combines the Mesopotamian geography — Babylon sat in the alluvial lowlands between rivers — with the prophetic imagery of chaos-water. In the NT, Babylon the Great comes from the waters (Rev 17:1) — the same cryptic geography of the empire of chaos.</p>", '2': "<p>A grim vision: the traitor betrays, the plunderer plunders. March, O Elam! Besiege, O Media! All the sighing she has caused I will bring to an end. The command to the Medes and Elamites is YHWH's war-summons — the same pattern as 13:17 (I am rousing the Medes). The end of Babylon's sighing — the suffering it has caused — is the goal of the judgment. In the NT, Babylon's fall in Rev 18 similarly ends the suffering of those who were killed for the word of God (Rev 6:10: how long, O Lord?). The divine bringing-to-an-end of oppression is the Servant's mission enacted at the cosmic level.</p>", '3': "<p>Isaiah's anguish at the vision: my body is racked with labor pains; I am too shaken to hear, too disturbed to see. The prophetic intercession takes the form of bodily suffering — the prophet bears in his body the weight of the message he delivers. The same visceral response appears at 16:11 (my heart moans like a lyre for Moab). The prophet's suffering at the vision of judgment is a small image of the divine mourning over judgment (Ezek 18:23, 33:11) and the Servant's bodily bearing of others' pain (53:4-6).</p>", '4': "<p>My mind reels; the evening I had longed for has been turned into dread. The reversal of the evening from anticipated rest to dread is the experience of those who live under the threat of judgment's arrival: the night brings anxiety, not relief. In the NT, the disciples in Gethsemane experience the same turning of anticipated rest (sleeping) into anguish (Matt 26:36-46) — the hour that came with dread rather than peace. The prophet's night of dread anticipates the darkest night of the Servant's suffering.</p>", '5': "<p>Set the table, spread the rugs, eat and drink — then: Rise up, princes, oil the shields! The scene cuts from banquet to battle stations — the sudden interruption of celebration by the alarm of war. This is precisely the scene in Dan 5:1-6: Belshazzar's feast interrupted by the handwriting on the wall, followed by the Median conquest (Dan 5:28-30). The Danielic narrative fulfills the Isaianic prophecy in vivid detail. In the NT, Jesus warns that the day of the Son of Man will come like a thief in the night, interrupting those who are eating and drinking (Matt 24:38-39, Luke 17:28).</p>", '6': "<p>YHWH stations a watchman — let him report what he sees. The watchman metaphor is central to the prophetic vocation (Ezek 3:17, 33:7: I have made you a watchman for Israel). The watchman watches and waits, alert for the signal that others miss. In the NT, Jesus commands watchfulness repeatedly (Matt 24:42-44, 25:13): be on guard, keep watch, for you do not know the hour. The church's eschatological posture is the watchman's posture — alert to the signs of the coming Lord.</p>", '7': "<p>The watchman saw a column of cavalry — riders in pairs, a caravan of donkeys, a caravan of camels — and he listened intently. The watchman's careful observation of the approaching column is the discipline of discernment: identifying what approaches before it arrives. The column of riders prefigures the NT imagery of the rider on the white horse (Rev 19:11-14) — but here the approaching riders bring judgment on Babylon, not the final victory of the Lamb. The watchman's discipline of patient, attentive watching is the contemplative ground of prophetic ministry.</p>", '8': "<p>The lookout called: My lord, I stand on the watchtower continually by day, and I keep my post every night. The watchman's faithfulness — continually by day, every night — is the model of the intercessor who does not give up (Isa 62:6-7: you who remind YHWH, give him no rest). In the NT, the persistent widow who keeps coming to the judge (Luke 18:1-8) is the parable form of this faithful watchman-prayer. The watchman does not abandon his post even when the night is long and nothing seems to move.</p>", '9': "<p>Fallen, fallen is Babylon! All the carved images of her gods lie shattered on the ground. The watchman's proclamation is one of the most significant prophetic announcements in the OT — it is quoted verbatim in Rev 14:8 (Fallen! Fallen is Babylon the Great!) and Rev 18:2. The double Fallen! is the intensified announcement of irreversible collapse. The destruction of Babylon's gods (all the carved images) is the theological core: YHWH's victory over Babylon is simultaneously the defeat of everything Babylon's gods claimed to guarantee — fertility, security, wisdom, sovereignty. The NT application: at the cross, Christ disarmed the rulers and authorities (Col 2:15), and at his return, Babylon the Great falls finally and completely.</p>", '10': "<p>O my people, crushed and winnowed — what I have heard from YHWH of hosts, the God of Israel, I now declare to you. The prophetic word of comfort addressed to the oppressed community (my people) immediately follows the announcement of Babylon's fall. The crushing and winnowing of the covenant community is the experience of exile — they have been ground down under Babylon's weight. But the watchman's announcement (v 9) is directed toward them: the fall of Babylon is good news for those who have suffered under it. In the NT, the announcement of Babylon's fall in Rev 14:8 is immediately followed by the call to the saints to endure (Rev 14:12) and the proclamation of the harvest of the earth (Rev 14:14-16).</p>", '11': "<p>The oracle of Dumah — a name that sounds like the Hebrew for silence/death (<em>dumah</em>). A voice calls from Seir: Watchman, what is left of the night? Seir is Edom. The question about the night's length is the anxious question of one waiting for dawn: how much longer until the darkness ends? In the Christological reading, the night of the exile and of all suffering under anti-God power is the dark through which the watchman watches. The question — what is left of the night? — is the eschatological question of the persecuted community in Rev 6:10: how long, O Lord?</p>", '12': "<p>The watchman answers: Morning is coming, but so is the night. If you would inquire, inquire; come back again. The answer is oracular — morning and night coexist in the watchman's reply. The mixed answer is not evasion but honest prophetic vision: light and darkness alternate before the final dawn. The NT equivalent: signs of the kingdom are present even now, but the night is not yet over; the day of the Lord has not yet come fully. The inquiry is the right response: keep asking, keep coming back. Jesus says ask, and it will be given; seek, and you will find; knock, and the door will be opened (Matt 7:7).</p>", '13': "<p>The oracle concerning Arabia — addressed to caravans of the Dedanites taking shelter in the thickets. Arabia was the trading-caravan territory south of Palestine. The judgment that sweeps through the empires reaches even the commercial routes of the desert. In the Christological framework, the reach of YHWH's judgment and redemption is universal: no commercial network, no desert trade route, no distant people is outside YHWH's concern. The NT equivalent is Acts 1:8: witnesses in Jerusalem, Judea, Samaria, and to the ends of the earth — the gospel moves through every trading network and every wilderness.</p>", '14': "<p>Bring water to the thirsty, O people of Tema; go out with food to meet the fugitives. The practical care for refugees — water to the thirsty, food to the fugitives — is the covenant obligation embedded in the prophetic oracle. In the NT, Jesus makes care for the hungry, thirsty, and stranger the criterion of judgment: as you did it to one of the least of these, you did it to me (Matt 25:35-40). The water and bread offered to Arabia's fugitives are a small type of the bread of life and living water that the Servant gives to all who are driven and desperate.</p>", '15': '<p>For they have fled from the swords, from the drawn bow, from the fury of battle. The refugees of Arabia are driven by the same military violence that sweeps through all the oracles of chapters 13-21. Their flight is neither political nor economic but existential: they flee for their lives. The NT: the disciples flee (Matt 10:23: when they persecute you in one city, flee to another) in the same pattern — the prophetic community takes refuge wherever it can until the greater city is established. The fugitives of Arabia point to the eschatological gathering of all refugees into the city that has foundations (Heb 11:10).</p>', '16': "<p>Within a year — reckoned as a hired worker counts a year — all the wealth of Kedar will come to an end. The hired-worker's year is the most precise measure of labor-time in the ancient world: a full year of work, counted to the day, with no extensions. YHWH's judgment is as precise as a work contract. In the NT, the appointed time of judgment is fixed: God has set a day on which he will judge the world with justice through the man he has appointed (Acts 17:31). The precision of prophetic timing reflects the precision of the divine calendar.</p>", '17': "<p>The remaining archers of Kedar will be greatly diminished, for YHWH the God of Israel has spoken. The oracle's ending is anchored in the divine identity: YHWH the God of Israel — not a local deity but the sovereign of all nations — has spoken. The nations of chapters 13-21 are all under the same divine sovereign whose word, once spoken, does not return empty (55:11). The God who judges Arabia is the God who redeems Israel and who, through Israel's Servant, will bless Egypt, Assyria, and Arabia alike.</p>"}, '22': {'1': "<p>The oracle of the Valley of Vision — the cryptic title for Jerusalem, the city that was the site of prophetic vision (cf. 2:1). Jerusalem, the city of YHWH's presence, is itself under judgment — the most painful oracle in the series, because this is the covenant community, not a foreign nation. What has come over you that you have all climbed up to the housetops? The rooftops in the ancient world were places of watching, of festivals, and of anxious observation. Jerusalem's people are on the rooftops — whether celebrating or in panic is ambiguous, which is part of the oracle's power.</p>", '2': "<p>You are a city full of uproar and celebration — but your slain were not killed by the sword, and your dead did not fall in battle. The deaths of Jerusalem's people were not honorable military deaths but the deaths of panic, flight, and starvation. The celebration (at apparent deliverance?) is hollow: those who died, died without the dignity of battle. The uproar of the city is the dark inverse of the joyful uproar of 12:6 (shout for joy, you who dwell in Zion). Jerusalem's wrong kind of noise shows that it missed the right moment for repentance.</p>", '3': "<p>All your commanders fled together; they were captured without a bow being drawn. The military leadership's cowardice — captured without a fight — is the specific shame of Jerusalem's leaders. In the NT, the disciples fled at Jesus' arrest (Matt 26:56: all the disciples deserted him and fled). The temporary failure of the disciples is the negative image of what the Servant accomplishes alone: when all fled, the Servant did not flee but went voluntarily to his suffering (53:7: he did not open his mouth).</p>", '4': "<p>I said: Turn away from me; let me weep bitterly; do not try to comfort me over the ruin of the daughter of my people. The prophet's grief over Jerusalem is the closest analogy in Isaiah to Jesus' weeping over Jerusalem (Luke 19:41-44: when Jesus saw the city, he wept over it). The daughter of my people in ruin is the same image as the desolate woman of 3:26 sitting on the ground. The refusal of comfort is the authentic grief of one who loves the city and sees what is coming — and the NT weeping of Jesus over Jerusalem is its fulfillment.</p>", '5': "<p>YHWH of hosts has a day of panic and trampling and confusion in the Valley of Vision — walls crashing down, a cry shattering against the mountain. The Day of YHWH applied to Jerusalem: the city of his presence is not exempt from his judgment. The shattering cry is the sound of the city's defense collapsing. The NT: Jesus warns explicitly that the stones of the temple will be thrown down (Matt 24:2), fulfilled in 70 CE. The Day of YHWH falls on Jerusalem precisely because it is the covenant city — the higher the privilege, the heavier the accountability.</p>", '6': "<p>Elam took up the quiver with chariots and cavalry, and Kir bared the shield. The armies surrounding Jerusalem are diverse — Elam to the east, Kir to the north. The coalition against Jerusalem is YHWH's instrument. In the NT, the destruction of Jerusalem in 70 CE by the Roman armies is interpreted by Jesus as YHWH's judgment (Luke 21:20-24: when you see Jerusalem surrounded by armies, know that its desolation has come). The nations that besiege Jerusalem are always, in prophetic interpretation, the instruments of a higher justice.</p>", '7': "<p>Your finest valleys were choked with chariots, and cavalry were posted at the city gates. The agricultural valleys of Judah — the source of Jerusalem's food supply — are blocked by enemy forces. The siege cuts off both escape and provision: the city is both trapped and starved. The NT: those who do not come under the Servant's provision will face exactly this condition — cut off from the source of life. But those who come to the one who says come to the waters (55:1) will never be cut off.</p>", '8': "<p>He stripped away Judah's defenses. In that day you turned to the arsenal in the House of the Forest. The House of the Forest (1 Kgs 7:2-5) was the great armory Solomon built — the symbol of human military preparedness. Jerusalem's crisis response is to turn to its weapons cache. The condemnation is not of the arsenal itself but of the priority: weapons before YHWH. In the NT pattern: those who trust in weapons and walls miss the true defense; the one who guards the city watches in vain unless YHWH watches (Ps 127:1).</p>", '9': "<p>You saw the gaps in the wall of the city of David and collected water into the lower pool. The engineering response to the siege: Hezekiah's famous water tunnel (2 Kgs 20:20, 2 Chr 32:2-4) redirected the Gihon spring to the Pool of Siloam, denying water to the besieging Assyrians. The historical detail shows that the crisis of chapter 22 is connected to the Assyrian siege of 701 BCE — the same crisis resolved by the miraculous deliverance of chapter 37. The water-engineering that preserved Jerusalem physically is a type of the living water that the Servant provides permanently.</p>", '10': "<p>You took inventory of Jerusalem's houses and demolished buildings to strengthen the wall. The dismantling of houses to reinforce the city wall — sacrificing private dwellings for collective defense — is the desperate pragmatism of siege conditions. The NT: the kingdom is built not by demolishing houses but by building what cannot be shaken (Heb 12:28). The human effort to fortify what God has already committed to protect reveals the chronic failure to trust YHWH rather than human engineering.</p>", '11': "<p>You built a cistern between the two walls, but you did not look to the one who made all this; you took no account of the one who planned it long ago. The specific accusation: you looked to the water cistern (human engineering) but not to YHWH (who both made the city and planned its history). The double accusation — did not look, took no account — is the fundamental covenant failure: sight and consideration are directed at the wrong object. The NT: seek first the kingdom of God and his righteousness, and all these things will be added to you (Matt 6:33) — the reversal of the Jerusalem leaders' priority inversion.</p>", '12': "<p>In that day the Lord GOD of hosts called for weeping and mourning, for shaving the head and sackcloth. The appropriate response to the coming judgment is prophetic lamentation — the bodily, public acknowledgment of grief and guilt that prepares for YHWH's intervention. The NT: blessed are those who mourn, for they shall be comforted (Matt 5:4). The lamentation that YHWH calls for is the gateway to the comfort that the gospel brings. Jerusalem's failure to mourn rightly is the specific sin of v 13.</p>", '13': '<p>But instead there was only celebration — slaughtering oxen, killing sheep, eating and drinking: Let us eat and drink, for tomorrow we die. The famous phrase let us eat and drink, for tomorrow we die is the response of those who, faced with imminent judgment, choose hedonism over repentance. Paul quotes it in 1 Cor 15:32 as the logical conclusion of a life without resurrection hope: if the dead are not raised, then eat, drink, and be merry. But because Christ has been raised (1 Cor 15:20), the right response to mortality is not hedonism but resurrection hope.</p>', '14': "<p>YHWH of hosts revealed this directly in my hearing: This guilt will never be atoned for while you live. The specific word about unforgivable guilt spoken against this community is one of the most severe in the prophetic corpus — stronger even than the hardening of 6:9-10. The guilt that cannot be atoned is not the guilt of ordinary sin but the guilt of willful, defiant, eyes-open rejection of YHWH's call to repentance (v 12) in favor of deliberate hedonism (v 13). The NT equivalent: the blasphemy against the Holy Spirit will not be forgiven (Matt 12:31-32) — the same pattern of guilt that persists because there is no repentance, not because the atoning work is insufficient.</p>", '15': "<p>Go to Shebna the steward who is in charge of the palace. Shebna is the chief minister (steward = <em>asher al-habayit</em>, the one over the house) of Hezekiah's administration. He represents the self-aggrandizing official who uses public office for personal glory. The specific accusation (v 16) — carving himself a magnificent tomb — shows that his concern is his own legacy rather than the kingdom's welfare. In the NT, the contrast is the Servant who made himself nothing (Phil 2:7) — the steward of YHWH's household who did not use his position for personal glory.</p>", '16': "<p>What gives you the right to be here? Who do you think you are, carving yourself a tomb on the heights — hewing a burial place in the rock? The two rhetorical questions assault Shebna's self-constructed identity. The magnificent tomb he is building for himself on the heights (a prime Jerusalem location) is the sign of his self-importance. In the NT, the tombs of the prophets that the scribes and Pharisees build and adorn (Matt 23:29) are the same self-aggrandizing monument-building — honoring the dead to establish their own religious status while refusing to receive the living prophets.</p>", '17': "<p>See — YHWH is about to hurl you away with a violent throw, O man; he will take hold of you and fling you far. The violence of the divine action against Shebna is the severity appropriate to the severity of his self-aggrandizement: the self-exalted is hurled low. In the NT pattern: everyone who exalts himself will be humbled (Luke 14:11). Shebna's violent ejection from office is the type of the removal of all false stewards when the true Steward-Servant assumes the position that rightly belongs to him.</p>", '18': "<p>He will ball you up and fling you like a stone across a wide open land; there you will die and your splendid chariots will be your shame. Death in a foreign land — the worst fate for an ancient Israelite who had invested so heavily in a Jerusalem tomb — is the exact reversal of Shebna's aspiration. The chariots that were symbols of status become symbols of shame: what you used to display your power will mark your disgrace. In the NT: what the world counts as gain, the Servant counts as loss (Phil 3:7-8).</p>", '19': "<p>I will remove you from your position and pull you down from your office. The divine removal of Shebna is the condition for Eliakim's appointment (v 20). The removal of the false steward makes room for the true one — the same pattern as the removal of Eli's priesthood (1 Sam 2:30-35) to make room for the faithful priest. In the Christological trajectory: the removal of inadequate mediators makes way for the one perfect mediator (Heb 9:11-15).</p>", '20': "<p>In that day I will summon my servant Eliakim son of Hilkiah. The title my servant (<em>avdi</em>) applied to Eliakim is the same title applied to the great Servant of chapters 42-53. Eliakim is a type of the eschatological Servant: faithful in the household, given the master's authority, opened to what no one can shut. The individual historical steward becomes a prophetic type of the true and final Steward of YHWH's house.</p>", '21': "<p>I will dress him in your robe and fasten your sash around him; I will hand your authority over to him, and he will be a father to the inhabitants of Jerusalem and to the house of Judah. The investiture — robe, sash, authority — is royal language: Eliakim receives what a king confers on his prime minister. The father to Jerusalem is the paternal-care title that describes the king's protective responsibility. In the Christological reading: Jesus is given the robe and authority of the eternal King, and he is a father to Jerusalem in the eschatological sense — the one who wanted to gather Jerusalem's children like a hen gathers her chicks (Matt 23:37).</p>", '22': '<p>I will lay on his shoulder the key of the house of David; what he opens no one will shut, and what he shuts no one will open. The key of the house of David is the most Christologically explicit verse in chapter 22 — it is quoted verbatim in Rev 3:7 as the description of the risen Christ: these are the words of him who is holy and true, who holds the key of David. What he opens no one will shut, and what he shuts no one will open. The key is not a physical key but the authority to open and close the house of YHWH — access to the covenant community, to salvation, to the kingdom. Jesus holds this key as the true and final Eliakim.</p>', '23': "<p>I will drive him in like a peg into a solid place, and he will become a throne of glory to his ancestral household. The peg driven into a solid place — an immovable fastener — is a metaphor for permanent appointment. Eliakim's position is secure, in contrast to Shebna's ejection. He becomes a throne of glory: the official becomes a seat of honor for his whole family. In the NT, the risen and enthroned Christ is the solid place — the cornerstone that the builders rejected (Ps 118:22, Matt 21:42) — into which all who trust him are built as living stones (1 Pet 2:4-5).</p>", '24': "<p>They will hang on him all the honor of his father's household — descendants and offshoots, every vessel from the smallest cups to the largest jars. The peg that Eliakim has become carries the whole household's weight and glory. The image of vessels hung on the peg — from cups to jars — is an image of the full community's dependence on the one appointed. In the NT, the Servant bears the whole household of faith: he is the one shepherd (John 10:16), the vine on which all branches depend (John 15:5), the cornerstone holding the whole building (Eph 2:20).</p>", '25': '<p>In that day the peg driven into the solid place will fail; it will be cut down and fall, and the load hanging on it will be cut off. The oracle ends with judgment: even the faithful Eliakim-type will ultimately fail — the peg is cut down and the load falls. This is the dark word that qualifies the typology: Eliakim is a type, not the antitype. Every human steward, however faithful, is finite and mortal. The peg that never fails is only the one described in Rev 3:7 — the one who holds the key of David and whose appointment is not temporal but eternal. Human types point to the divine reality and then fail, ensuring that the hope is fixed not on the type but on the one who fulfills it.</p>'}}

def main():
    data = load_comm('mkt-christ', 'isaiah')
    merge_comm(data, ISAIAH)
    chs = sorted(data.keys(), key=lambda x: int(x))
    total_v = sum(len(data[c]) for c in chs)
    print(f'Isaiah christ: {len(chs)} chapters, {total_v} verses')
    save_comm('mkt-christ', 'isaiah', data)

if __name__ == '__main__':
    main()
